    """Replace atomico cross-platform. Fallback para WinError 5 (archivo bloqueado)."""
    try:
        tmp_path.replace(dest_path)
    except OSError:
        import shutil
        try:
            shutil.copy2(str(tmp_path), str(dest_path))
        except Exception:
            dest_path.write_text(tmp_path.read_text(encoding="utf-8"), encoding="utf-8")
        finally:
            try:
                tmp_path.unlink(missing_ok=True)

