   def _get_frame_offset(self, frame) -> tuple:
       """Get the absolute viewport offset of a frame."""
       try:
           # Try to get frame element and its bounding box
           if frame == self.page.main_frame:
               return (0, 0)

           frame_element = frame.frame_element()
           box = frame_element.bounding_box()
           if box:
               return (box['x'], box['y'])

           # Fallback: try to calculate from parent frames
           return (0, 0)
       except:
           return (0, 0)

